\begin{algorithm}[!htb]
    \caption{Primal-dual Newton Method}
    \label{alg:PDN}
    \begin{algorithmic}[1]
        \STATE Input: $\mathbf{A}\in\mathbb{R}_+^{m\times n}$, $C>0$.
        \IF{$\|\mathbf{A}\|_{1,\infty}\leq C$}
            \STATE \textbf{return} $\mathbf{A}$
        \ENDIF
        \STATE \textbf{Initialize} $\lambda^0=(\sum_{i=1}^{m}\|\bm{a}_i\|_\infty-C)/m$, $\boldsymbol\mu^0=\mathbf{0}_{m\times 1}$ and $\beta_i^0=1/|\mathcal{I}(\mu_i^0)|$ for $i\in[m]$.

        \FOR{$k=0,1,2,\dots$}
        \STATE Update $\mathcal{B}^k=\{i|\|\bm{a}_i\|_1>\lambda^k\}$.

        \STATE Update $\mu_i^k$ 
        \begin{equation}\label{eq:alg_update_mu}
            \mu_i^{k+1} =\begin{cases}
                \mu_i^k-\beta_i^k\nabla_i\mathcal{L}\left(\boldsymbol\mu^k,\lambda^k\right), &\text{ if }i\in\mathcal{B}^k\\
                0, &\text{ otherwise }
            \end{cases}
        \end{equation}
        \STATE Compute $\beta_i^{k+1}=1/|\mathcal{I}(\mu_i^{k+1})|$ for $i\in\mathcal{B}^k$.
        \STATE Update $\lambda^k$
            \begin{equation}\label{eq:alg_update_lambda}
                \lambda^{k+1} = \lambda^k + \frac{\left[\sum_{i\in\mathcal{B}^k}\mu_i^{k+1}-C\right]_+}{\sum_{i\in\mathcal{B}^k}\beta_i^{k+1}}.
            \end{equation}
        \IF{$|\sum_{i\in\mathcal{B}^k}\mu_i^{k+1}-C|\leq0$}

            \STATE \textbf{Break}
        \ENDIF

        \ENDFOR
        \STATE \textbf{return} $\mathbf{W}^*=\min(\mathbf{A},\boldsymbol\mu^k\bm{1}_{1\times n})$. 
    \end{algorithmic}
\end{algorithm}
